Bash(timeout 10 node -e "
const {JSDOM} = require\('jsdom'\);
const DOM = new JSDOM\('<!DOCTYPE html>'\);
const van = require\('mini-van-plate'\);
const {tags} = van.vanWithDoc\(DOM.window.document\);

// Test basic tag creation
console.log\('div:', typeof tags.div\);
console.log\('svg:', typeof tags.svg\);
console.log\('path:', typeof tags.path\);
console.log\('clipPath:', typeof tags.clipPath\);
console.log\('defs:', typeof tags.defs\);

// Test creating clipPath element
try {
  var p = tags.path\({d: 'M 0 0 L 1 1'}\);
  console.log\('path el:', p.outerHTML\);
  var cp = tags.clipPath\({id: 'test', clipPathUnits: 'objectBoundingBox'}, p\);
  console.log\('clipPath el:', cp.outerHTML\);
  var d = tags.defs\(cp\);
  console.log\('defs el:', d.outerHTML\);
  var s = tags.svg\({xmlns: 'http://www.w3.org/2000/svg', width: '0', height: '0'}, d\);
  console.log\('svg el:', s.outerHTML\);
} catch\(e\) {
  console.error\('ERROR:', e.message\);
}
" 2>&1)
